export default {
  name: 'DocumentView',
  data() {
    return {
      sections: [{
        title: '1. Objetivo o Propósito',
        content: ''
      }, {
        title: '2. Alcance',
        content: ''
      }, {
        title: '3. Responsabilidades',
        content: ''
      }, {
        title: '4. Normativa',
        content: ''
      }, {
        title: '5. Procedimiento',
        content: ''
      }, {
        title: '6. Anexos',
        content: ''
      }, {
        title: '7. Términos y Referencias',
        content: ''
      }]
    };
  },
  methods: {
    generateDocument() {
      // Crear contenido HTML simple
      let htmlContent = `
        <!DOCTYPE html>
        <html>
        <head>
            <meta charset="UTF-8">
            <title>Pago a Proveedores - ASADOS EL CARRETÓN</title>
            <style>
                body { font-family: Arial, sans-serif; margin: 40px; line-height: 1.6; }
                h1 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; }
                h2 { color: #34495e; margin-top: 30px; border-left: 4px solid #3498db; padding-left: 10px; }
                .section { margin-bottom: 30px; }
            </style>
        </head>
        <body>
            <h1>PROCEDIMIENTO DE PAGO A PROVEEDORES</h1>
      `;

      // Agregar cada sección
      this.sections.forEach(section => {
        if (section.content.trim()) {
          htmlContent += `
            <div class="section">
              <h2>${section.title}</h2>
              <p>${section.content.replace(/\n/g, '<br>')}</p>
            </div>
          `;
        }
      });
      htmlContent += `</body></html>`;

      // Crear y descargar el archivo
      this.downloadFile(htmlContent, 'Pago_Proveedores.html', 'text/html');
      alert('Documento generado exitosamente!');
    },
    showSampleData() {
      this.sections = [{
        title: '1. Objetivo o Propósito',
        content: 'Establecer el procedimiento de pagos a nuestros proveedores con políticas claras y definidas para aprovechar los descuentos por pago oportuno.'
      }, {
        title: '2. Alcance',
        content: 'Este procedimiento abarca el proceso a partir del requerimiento de pago por la adquisición del bien, insumos o servicios, hasta el pago mediante la transferencia bancaria.'
      }, {
        title: '3. Responsabilidades',
        content: '1. Jefe Administrativo\n2. Gerente General\n3. Proveedor\n4. Encargado de Almacén\n5. Cajero'
      }, {
        title: '4. Normativa',
        content: 'Las compras a crédito se establecerán de mutuo acuerdo con un periodo máximo de quince días laborables. El proveedor deberá emitir prefactura de compra para corroborar la orden de compra.'
      }, {
        title: '5. Procedimiento',
        content: 'El administrador revisa las cuentas por pagar próximas a vencer y elabora la lista de proveedores a pagar. El Gerente General revisa y autoriza los pagos.'
      }, {
        title: '6. Anexos',
        content: 'Formato de listado de pago a proveedores\nRegistro de facturas pendientes'
      }, {
        title: '7. Términos y Referencias',
        content: 'RTN: Registro Tributario Nacional\nPrefactura: Documento previo a la factura definitiva'
      }];
      alert('Datos de ejemplo cargados!');
    },
    downloadFile(content, fileName, contentType) {
      const blob = new Blob([content], {
        type: contentType
      });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    }
  }
};
